import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:8000',
  withCredentials: true, // Для работы с куками
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  }
});

// Интерцептор для обработки ошибок
api.interceptors.response.use(
  response => response,
  error => {
    // Если ошибка 401 (Unauthorized), можно редиректить на страницу логина
    if (error.response && error.response.status === 401) {
      localStorage.removeItem('token');
      // Если вы используете React Router, здесь можно сделать редирект
      // window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

export default api;

// Экспортируем отдельные сервисы для различных API

// API для аутентификации
export const authApi = {
  login: (address, network, signature) => api.post('/users/login', { address, network, signature }),
  logout: () => api.post('/users/logout'),
  getCurrentUser: () => api.get('/users/me'),
  testAuth: () => api.get('/users/test-auth')
};

// API для токенов
export const tokensApi = {
  getAllTokens: () => api.get('/tokens'),
  getToken: (id) => api.get(`/tokens/${id}`),
  getTokensByNetwork: (networkId) => api.get(`/tokens/network/${networkId}`)
};

// API для стейкинга
export const stakingApi = {
  getStakingList: () => api.get('/staking'),
  getStaking: (id) => api.get(`/staking/${id}`),
  stakeTokens: (tokenId, amount) => api.post('/staking', null, { params: { token_id: tokenId, amount } }),
  getStakingBalance: () => api.get('/staking/balance')
};
